          isInvalid={getHasError(emailFieldName)}
          label={t('common:email')}
          name={emailFieldName}
          onBlur={handleBlur}
          onChange={handleChange}
          ref={(e) => {
            mailRef(e);
            emailRef.current = e;
          }}
          value={ticketDetails.email}
        />
      </div>

      <AttendeeEmployment
        currentlyEmployedFieldName={currentlyEmployedFieldName}
        employerNameFieldName={employerNameFieldName}
        fieldConfiguration={actionPage?.fieldConfiguration}
        occupationFieldName={occupationFieldName}
        occupationOptions={filteredOccupationOptions}
        onBlur={handleBlur}
        onChange={handleChange}
        onCurrentlyEmployedChange={handleRadioChange}
        ticketDetails={ticketDetails}
      />
    </>
  );
};

