import { PublicActionPage } from '@domain/publicActionPage';
import { useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { FormPhoneInputControl } from 'src/builder/PublicActionPage/components/PhoneInputControl';
import { CommunicationsConsentPhone } from './CommunicationsConsentPhone';

type Props = {
  actionPage?: PublicActionPage;
  isPreview?: boolean;
};

const phoneLabelMap: Record<string, string> = {
  phone: 'Phone',
  home: 'Home Phone',
  cell: 'Cell Phone',
  mobile: 'Mobile Phone',
};

export const PhoneField = ({ actionPage, isPreview = false }: Props) => {
  const { setValue, watch } = useFormContext();
  const donorProfile = isPreview ? null : watch('donorProfile');
  const isInternational = actionPage?.fieldConfiguration.regions?.includes('IN');

  const {
    displayCommunicationsConsent,
    displayEmail,
    displayPhone,
    phoneLabel,
    requireEmailOrPhone,
    requirePhone,
  } = actionPage?.fieldConfiguration || {};

  const phoneLabelValue = useMemo(() => {
    if (phoneLabel && phoneLabelMap[phoneLabel]) {
      return phoneLabelMap[phoneLabel];
    }
    return 'Phone';
  }, [phoneLabel]);

  const isPhoneRequired = useMemo(() => {
    return requirePhone && !requireEmailOrPhone;
  }, [requireEmailOrPhone, requirePhone]);

  return (displayPhone ||
    requirePhone ||
    requireEmailOrPhone ||
    (!displayEmail && !displayPhone)) &&
    (!donorProfile?.phone || displayCommunicationsConsent) ? (
    <div className="flex flex-col items-stretch">
      {!donorProfile?.phone ? (
        <FormPhoneInputControl
          isInternational={isInternational}
          isRequired={isPhoneRequired}
          label={phoneLabelValue}
          onCountryChange={(country) => setValue('addressAttributes.country', country)}
        />
      ) : null}
      {displayCommunicationsConsent ? (
        <CommunicationsConsentPhone
          communicationsConsentText={actionPage?.fieldConfiguration.communicationsConsentText}
          name={actionPage?.account.displayName}
        />
      ) : null}
    </div>
  ) : null;
};

